}

// MARK: - Milestones

struct MilestonesSectionView: View {
    let milestones: [String]

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            SectionHeader(emoji: "⭐", title: "Milestones & Moments", subtitle: "")
