    }
}

// MARK: - Mood arc

struct MoodArcView: View {
    let text: String

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            SectionHeader(emoji: "🌈", title: "Mood & Behavior", subtitle: "")
            Text(text).font(.body).fixedSize(horizontal: false, vertical: true)
        }
        .padding(.horizontal)
    }
}

// MARK: - Pediatrician summary

struct PediatricianSummaryView: View {
    let text: String
    @State private var isExpanded = false

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            Button(action: { withAnimation { isExpanded.toggle() } }) {
                HStack {
                    SectionHeader(emoji: "👨‍⚕️", title: "For your next visit", subtitle: "")
                    Spacer()
                    Image(systemName: isExpanded ? "chevron.up" : "chevron.down")
                        .foregroundColor(.secondary)
                        .font(.caption)
                }
            }
            .buttonStyle(.plain)
            if isExpanded {
                Text(text)
                    .font(.body.monospaced())
                    .foregroundColor(.secondary)
                    .fixedSize(horizontal: false, vertical: true)
                    .padding()
                    .background(Color(.secondarySystemBackground))
                    .clipShape(RoundedRectangle(cornerRadius: 10))
            }
        }
        .padding(.horizontal)
    }
}

// MARK: - Share card

struct ShareCardView: View {
    let tweet: String
    let babyName: String

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            SectionHeader(emoji: "✨", title: "Share", subtitle: "")
            Text(tweet)
                .font(.body)
                .padding()
                .frame(maxWidth: .infinity, alignment: .leading)
                .background(Color(.secondarySystemBackground))
                .clipShape(RoundedRectangle(cornerRadius: 12))
            ShareLink(item: tweet) {
                Label("Share", systemImage: "square.and.arrow.up")
            }
            .buttonStyle(.bordered)
        }
        .padding(.horizontal)
    }
}

// MARK: - Shared sub-views

struct SectionHeader: View {
    let emoji: String
    let title: String
    let subtitle: String

    var body: some View {
        HStack(alignment: .firstTextBaseline, spacing: 4) {
            Text("\(emoji) \(title)").font(.headline)
            if !subtitle.isEmpty {
                Text("· \(subtitle)")
                    .font(.subheadline)
                    .foregroundColor(.secondary)
            }
        }
    }
}

struct TimelineRow: View {
    let time: String
    let title: String
    let detail: String?

    var body: some View {
        HStack(alignment: .top, spacing: 12) {
            Text(time)
                .font(.caption.monospacedDigit())
                .foregroundColor(.secondary)
                .frame(width: 62, alignment: .trailing)
            VStack(alignment: .leading, spacing: 1) {
                Text(title).font(.subheadline)
                if let d = detail {
                    Text(d).font(.caption).foregroundColor(.secondary)
                }
            }
        }
    }
}

struct FlagRow: View {
    let text: String

    var body: some View {
        HStack(spacing: 6) {
            Image(systemName: "exclamationmark.triangle.fill")
                .foregroundColor(.orange)
                .font(.caption)
            Text(text).font(.caption).foregroundColor(.orange)
        }
    }
}

// MARK: - Legacy fallback (old backend responses)

struct LegacySummaryView: View {
    let structured: DaySummary.Structured

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            if let glance = structured.glance, !glance.isEmpty {
                ScrollView(.horizontal, showsIndicators: false) {
                    HStack {
                        ForEach(glance, id: \.self) { item in
                            Text(item)
                                .font(.caption)
                                .padding(.horizontal, 10)
                                .padding(.vertical, 5)
                                .background(Color.accentColor.opacity(0.15))
                                .clipShape(Capsule())
                        }
                    }
                    .padding(.horizontal)
                }
            }
            if let eating = structured.eating {
                VStack(alignment: .leading, spacing: 4) {
                    Text("🍼 Feeding").font(.headline)
                    if let s = eating.summary { Text(s).font(.body) }
                }
                .padding(.horizontal)
            }
            if let nap = structured.nap {
                VStack(alignment: .leading, spacing: 4) {
                    Text("😴 Sleep").font(.headline)
                    if let s = nap.summary { Text(s).font(.body) }
                }
                .padding(.horizontal)
            }
            if let milestone = structured.milestone, let items = milestone.items, !items.isEmpty {
                VStack(alignment: .leading, spacing: 4) {
                    Text("⭐ Milestones").font(.headline)
                    ForEach(items, id: \.self) { Text("• \($0)").font(.body) }
                }
                .padding(.horizontal)
            }
        }
    }
}
